<!DOCTYPE html>
<html>
<head>
  <title>Personal Expense Tracker</title>
  <style>
    body { font-family: sans-serif; }
    #container { display: flex; }
    #form-area { width: 30%; padding: 10px; border: 1px solid #ccc; }
    #list-area { width: 70%; padding: 10px; border: 1px solid #ccc; overflow-y: auto; }
    .expense { margin-bottom: 5px; }
    .cat-total { font-weight: bold; }
  </style>
</head>
<body>

  <h1>Personal Expense Tracker</h1>

  <div id="container">
    <div id="form-area">
      <form id="expense-form">
        <label for="amount">Amount:</label>
        <input type="number" id="amount" step="0.01"><br><br>

        <label for="category">Category:</label>
        <select id="category">
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select><br><br>

        <label for="date">Date:</label>
        <input type="date" id="date"><br><br>

        <label for="note">Note (optional):</label>
        <textarea id="note"></textarea><br><br>

        <button id="add-expense">Add Expense</button>
        <span id="form-error"></span>
      </form>
    </div>

    <div id="list-area">
      <h2>Expenses</h2>
      <ul class="expenses"></ul>
      <p id="total">0.00</p>
      <div class="cat-totals"></div>

      <label for="filter-category">Category:</label>
      <select id="filter-category">
        <option value="all">All</option>
      </select><br>

      <label for="filter-from">From:</label>
      <input type="date" id="filter-from"><br>

      <label for="filter-to">To:</label>
      <input type="date" id="filter-to"><br>

      <div class="filter-controls"></div>
    </div>
  </div>

  <script>
    const expenseForm = document.getElementById('expense-form');
    const expensesList = document.querySelector('.expenses');
    const totalElement = document.getElementById('total');
    const categoryTotalsContainer = document.querySelector('.cat-totals');
    const filterCategorySelect = document.getElementById('filter-category');
    const filterFromInput = document.getElementById('filter-from');
    const filterToInput = document.getElementById('filter-to');

    let expenses = [];

    function renderExpenses() {
      expensesList.innerHTML = '';
      let visibleExpenses = [];

      if (filterCategorySelect.value === 'all') {
        visibleExpenses = expenses;
      } else {
        visibleExpenses = expenses.filter(expense => expense.category === filterCategorySelect.value);
      }

      visibleExpenses.forEach(expense => {
        const listItem = document.createElement('li');
        listItem.classList.add('expense');
        listItem.innerHTML = `
          ${expense.amount.toFixed(2)} ${expense.category} - ${expense.date}
          <button class="exp-del" data-id="${expense.id}">Delete</button>
        `;
        expensesList.appendChild(listItem);
      });

      updateCategoryTotals();
      updateTotal();
    }

    function updateTotal() {
      let total = 0;
      visibleExpenses.forEach(expense => total += expense.amount);
      totalElement.textContent = total.toFixed(2);
    }

    function updateCategoryTotals() {
      const categoryMap = new Map();
      expenses.forEach(expense => {
        if (!categoryMap.has(expense.category)) {
          categoryMap.set(expense.category, 0);
        }
        categoryMap.set(expense.category, categoryMap.get(expense.category) + expense.amount);
      });

      visibleExpenses.forEach(expense => {
        const cat = expense.category;
        if (categoryMap.has(cat)) {
          const element = document.createElement('div');
          element.classList.add('cat-total');
          element.setAttribute('data-cat', cat);
          element.textContent = `${categoryMap.get(cat).toFixed(2)}`;
          categoryTotalsContainer.appendChild(element);
        }
      });
    }

    function addExpense(event) {
      event.preventDefault();
      const amount = parseFloat(document.getElementById('amount').value);
      const category = document.getElementById('category').value;
      const date = document.getElementById('date').value;
      const note = document.getElementById('note').value || '';

      if (isNaN(amount) || amount <= 0 || !date) {
        document.getElementById('form-error').textContent = 'Please enter a valid amount and date.';
        return;
      }

      const newExpense = { id: Date.now(), amount, category, date, note };
      expenses.push(newExpense);
      renderExpenses();
      document.getElementById('form-error').textContent = '';
      document.getElementById('amount').value = '';
    }

    function deleteExpense(event) {
      const id = event.target.dataset.id;
      const index = expenses.findIndex(expense => expense.id === parseInt(id));
      if (index !== -1) {
        expenses.splice(index, 1);
        renderExpenses();
      }
    }

    expenseForm.addEventListener('submit', addExpense);
    document.querySelectorAll('.exp-del').forEach(button => button.addEventListener('click', deleteExpense));

    // Load from localStorage on page load
    window.onload = () => {
      const storedExpenses = localStorage.getItem('expenses');
      if (storedExpenses) {
        expenses = JSON.parse(storedExpenses);
        renderExpenses();
      }
    };

    // Save to localStorage whenever expenses change
    expenses.forEach(expense => {
      localStorage.setItem(String(expense.id), JSON.stringify(expense));
    });
  </script>

</body>
</html>
